import React from 'react';
import { FormData } from '../types';

interface StoreInfoFormProps {
  formData: FormData;
  onFormDataChange: (updates: Partial<FormData>) => void;
}

const StoreInfoForm: React.FC<StoreInfoFormProps> = ({ formData, onFormDataChange }) => {
  return (
    <div style={{
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
      gap: 'var(--space-2)',
      marginBottom: 'var(--space-3)',
      background: 'var(--color-bg-alt)',
      padding: 'var(--space-3)',
      borderRadius: 'var(--radius)'
    }}>
      <div>
        <label htmlFor="storeNumber" style={{ display: 'block', marginBottom: '4px', fontWeight: 'bold' }}>
          Store Number:
        </label>
        <input
          type="text"
          id="storeNumber"
          value={formData.storeNumber}
          onChange={(e) => onFormDataChange({ storeNumber: e.target.value })}
          style={{
            width: '100%',
            padding: '8px',
            border: '1px solid #ccc',
            borderRadius: 'var(--radius)',
            fontSize: '14px'
          }}
          required
        />
      </div>
      <div>
        <label htmlFor="storeManager" style={{ display: 'block', marginBottom: '4px', fontWeight: 'bold' }}>
          Store Manager:
        </label>
        <input
          type="text"
          id="storeManager"
          value={formData.storeManager}
          onChange={(e) => onFormDataChange({ storeManager: e.target.value })}
          style={{
            width: '100%',
            padding: '8px',
            border: '1px solid #ccc',
            borderRadius: 'var(--radius)',
            fontSize: '14px'
          }}
          required
        />
      </div>
      <div>
        <label htmlFor="date" style={{ display: 'block', marginBottom: '4px', fontWeight: 'bold' }}>
          Date:
        </label>
        <input
          type="date"
          id="date"
          value={formData.date}
          onChange={(e) => onFormDataChange({ date: e.target.value })}
          style={{
            width: '100%',
            padding: '8px',
            border: '1px solid #ccc',
            borderRadius: 'var(--radius)',
            fontSize: '14px'
          }}
          required
        />
      </div>
    </div>
  );
};

export default StoreInfoForm;
